@* Toolbar row with sort dropdown and results summary *@

<div class="d-flex flex-wrap justify-content-between align-items-center mb-3 gap-2">
    <div class="d-flex align-items-center gap-2">
        <label class="form-label mb-0 fw-semibold" for="sortSelect">Sort by:</label>
        <select id="sortSelect" class="form-select form-select-sm" style="width: auto;"
                value="@SortBy" @onchange="HandleSortChanged">
            <option value="price_asc">Price: Low to High</option>
            <option value="price_desc">Price: High to Low</option>
            <option value="name_asc">Name: A–Z</option>
            <option value="rating_desc">Rating: Highest</option>
        </select>
    </div>

    <span class="text-muted small">
        @if (TotalCount > 0)
        {
            var start = (Page - 1) * PageSize + 1;
            var end = Math.Min(Page * PageSize, TotalCount);
            <text>Showing @start–@end of @TotalCount products</text>
        }
        else
        {
            <text>No products</text>
        }
    </span>
</div>

@code {
    [Parameter]
    public string SortBy { get; set; } = "price_asc";

    [Parameter]
    public int TotalCount { get; set; }

    [Parameter]
    public int Page { get; set; } = 1;

    [Parameter]
    public int PageSize { get; set; } = 12;

    [Parameter]
    public EventCallback<string> OnSortChanged { get; set; }

    private async Task HandleSortChanged(ChangeEventArgs e)
    {
        await OnSortChanged.InvokeAsync(e.Value?.ToString() ?? "price_asc");
    }
}

@* Pagination controls: Previous, numbered pages, Next *@

@if (TotalPages > 1)
{
    <nav aria-label="Product pagination" class="mt-4">
        <ul class="pagination justify-content-center">
            <li class="page-item @(Page <= 1 ? "disabled" : "")">
                <button class="page-link" @onclick="() => GoToPage(Page - 1)" disabled="@(Page <= 1)">
                    Previous
                </button>
            </li>

            @foreach (var pageNum in GetPageNumbers())
            {
                <li class="page-item @(pageNum == Page ? "active" : "")">
                    <button class="page-link" @onclick="() => GoToPage(pageNum)">
                        @pageNum
                    </button>
                </li>
            }

            <li class="page-item @(Page >= TotalPages ? "disabled" : "")">
                <button class="page-link" @onclick="() => GoToPage(Page + 1)" disabled="@(Page >= TotalPages)">
                    Next
                </button>
            </li>
        </ul>
    </nav>
}

@code {
    [Parameter]
    public int Page { get; set; } = 1;

    [Parameter]
    public int TotalCount { get; set; }

    [Parameter]
    public int PageSize { get; set; } = 12;

    [Parameter]
    public EventCallback<int> OnPageChanged { get; set; }

    private int TotalPages => PageSize > 0 ? (int)Math.Ceiling((double)TotalCount / PageSize) : 1;

    private async Task GoToPage(int page)
    {
        if (page >= 1 && page <= TotalPages && page != Page)
        {
            await OnPageChanged.InvokeAsync(page);
        }
    }

    /// <summary>
    /// Returns a window of page numbers around the current page, with ellipsis gaps
    /// replaced by showing at most ~7 numbered buttons.
    /// </summary>
    private IEnumerable<int> GetPageNumbers()
    {
        const int maxVisible = 7;
        if (TotalPages <= maxVisible)
        {
            return Enumerable.Range(1, TotalPages);
        }

        var pages = new HashSet<int> { 1, TotalPages };
        int start = Math.Max(2, Page - 1);
        int end = Math.Min(TotalPages - 1, Page + 1);
        for (int i = start; i <= end; i++)
            pages.Add(i);

        return pages.OrderBy(p => p);
    }
}

