+@page "/catalog"
+@using sv_fce71e53032a4354a2b6d3c1a9d7048b.Components.Catalog
+@rendermode InteractiveServer
+@inject IProductService ProductService
+
+<PageTitle>Product Catalog</PageTitle>
+
+<h3 class="mb-3">Product Catalog</h3>
+
+@if (errorMessage is not null)
+{
+    <div class="alert alert-danger" role="alert">
+        <strong>Error:</strong> @errorMessage
+        <button class="btn btn-sm btn-outline-danger ms-2" @onclick="RetryLoad">Retry</button>
+    </div>
+}
+else
+{
+    <div class="catalog-layout">
+        @* Left sidebar — filters *@
+        <aside class="catalog-sidebar-column">
+            <CatalogSidebar Categories="categories"
+                            CurrentFilter="filter"
+                            OnFilterApplied="HandleFilterApplied" />
+        </aside>
+
+        @* Main content area *@
+        <main class="catalog-main-column">
+            @if (isLoading)
+            {
+                <div class="d-flex justify-content-center align-items-center py-5">
+                    <div class="spinner-border text-primary" role="status">
+                        <span class="visually-hidden">Loading products…</span>
+                    </div>
+                    <span class="ms-2">Loading products…</span>
+                </div>
+            }
+            else
+            {
+                <CatalogToolbar SortBy="@sortBy"
+                                TotalCount="@result.TotalCount"
+                                Page="@result.Page"
+                                PageSize="@result.PageSize"
+                                OnSortChanged="HandleSortChanged" />
+
+                <ProductGrid Products="@result.Items"
+                             OnProductSelected="HandleProductSelected"
+                             OnAddToCart="HandleAddToCart" />
+
+                <CatalogPagination Page="@result.Page"
+                                   TotalCount="@result.TotalCount"
+                                   PageSize="@result.PageSize"
+                                   OnPageChanged="HandlePageChanged" />
+            }
+        </main>
+    </div>
+}
+
+@code {
+    /// <summary>
+    /// Raised when a product card is clicked (not Add to Cart) so the parent or
+    /// host can navigate to a detail page.
+    /// </summary>
+    [Parameter]
+    public EventCallback<Product> OnProductSelected { get; set; }
+
+    private List<string> categories = [];
+    private ProductFilter filter = new(null, null, null, false);
+    private PagedResult<Product> result = new([], 0, 1, 12);
+    private string sortBy = "price_asc";
+    private int currentPage = 1;
+    private const int PageSize = 12;
+
+    private bool isLoading = true;
+    private string? errorMessage;
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadData();
+    }
+
+    private async Task LoadData()
+    {
+        try
+        {
+            isLoading = true;
+            errorMessage = null;
+
+            var categoriesTask = ProductService.GetCategoriesAsync();
+            var searchTask = ProductService.SearchAsync(filter, sortBy, currentPage, PageSize);
+
+            await Task.WhenAll(categoriesTask, searchTask);
+
+            categories = await categoriesTask;
+            result = await searchTask;
+        }
+        catch (Exception ex)
+        {
+            errorMessage = ex.Message;
+        }
+        finally
+        {
+            isLoading = false;
+        }
+    }
+
+    private async Task SearchProducts()
+    {
+        try
+        {
+            isLoading = true;
+            errorMessage = null;
+            result = await ProductService.SearchAsync(filter, sortBy, currentPage, PageSize);
+        }
+        catch (Exception ex)
+        {
+            errorMessage = ex.Message;
+        }
+        finally
+        {
+            isLoading = false;
+        }
+    }
+
+    private async Task HandleFilterApplied(ProductFilter newFilter)
+    {
+        filter = newFilter;
+        currentPage = 1;
+        await SearchProducts();
+    }
+
+    private async Task HandleSortChanged(string newSort)
+    {
+        sortBy = newSort;
+        currentPage = 1;
+        await SearchProducts();
+    }
+
+    private async Task HandlePageChanged(int page)
+    {
+        currentPage = page;
+        await SearchProducts();
+    }
+
+    private async Task HandleProductSelected(Product product)
+    {
+        await OnProductSelected.InvokeAsync(product);
+    }
+
+    private async Task HandleAddToCart(Product product)
+    {
+        // Placeholder for add-to-cart logic
+        await Task.CompletedTask;
+    }
+
+    private async Task RetryLoad()
+    {
+        await LoadData();
+    }
+}
+

